// NoteItem.server.js - runs on server
import { NoteContent } from './NoteContent.client';

export async function NoteItem({ id }) {
  const note = await fetchNoteFromDB(id);

  return (
    <article>
      <h2>{note.title}</h2>
      <NoteContent content={note.body} />
    </article>
  );
}
